#!/usr/bin/env python3
# Harness: session state -- a visible checklist for the current line of work.
"""
s03_todo_write.py - Session State

This chapter keeps TodoWrite, but with a clearer boundary:

- todos are short-lived session guidance
- they are not the durable task graph

That distinction matters later when we add persistent tasks.
"""

from __future__ import annotations

from pathlib import Path

from agents._shared import Tool, ToolRegistry, base_tools, get_model, make_client, repl, run_loop


class TodoManager:
    def __init__(self) -> None:
        self.items: list[dict[str, str]] = []

    def update(self, todos: list[dict[str, str]]) -> str:
        if len(todos) > 20:
            raise ValueError("Max 20 todo items")
        in_progress = 0
        normalized: list[dict[str, str]] = []
        for index, item in enumerate(todos, start=1):
            content = str(item.get("content", "")).strip()
            status = str(item.get("status", "pending")).lower()
            active_form = str(item.get("active_form", "")).strip()
            if not content:
                raise ValueError(f"Todo {index}: content is required")
            if status not in {"pending", "in_progress", "completed"}:
                raise ValueError(f"Todo {index}: invalid status {status!r}")
            if status == "in_progress":
                in_progress += 1
                if not active_form:
                    raise ValueError(f"Todo {index}: active_form required for in_progress")
            normalized.append(
                {
                    "content": content,
                    "status": status,
                    "active_form": active_form,
                }
            )
        if in_progress > 1:
            raise ValueError("Only one todo can be in_progress")
        self.items = [] if normalized and all(t["status"] == "completed" for t in normalized) else normalized
        return self.render()

    def render(self) -> str:
        if not self.items:
            return "No open session todos."
        lines: list[str] = []
        for item in self.items:
            marker = {
                "pending": "[ ]",
                "in_progress": "[>]",
                "completed": "[x]",
            }[item["status"]]
            suffix = f" <- {item['active_form']}" if item["status"] == "in_progress" else ""
            lines.append(f"{marker} {item['content']}{suffix}")
        done = sum(1 for item in self.items if item["status"] == "completed")
        lines.append(f"\n({done}/{len(self.items)} completed)")
        return "\n".join(lines)


WORKDIR = Path.cwd()
MODEL = get_model()
CLIENT = make_client()
SYSTEM = f"""You are a coding agent at {WORKDIR}.
Use todo_write for multi-step work.
Treat the todo list as the session checklist, not the long-lived project task graph.
Keep exactly one item in_progress."""

TODOS = TodoManager()
REGISTRY = ToolRegistry(
    base_tools(WORKDIR)
    + [
        Tool(
            name="todo_write",
            description="Update the session todo list.",
            input_schema={
                "type": "object",
                "properties": {
                    "todos": {
                        "type": "array",
                        "items": {
                            "type": "object",
                            "properties": {
                                "content": {"type": "string"},
                                "status": {
                                    "type": "string",
                                    "enum": ["pending", "in_progress", "completed"],
                                },
                                "active_form": {"type": "string"},
                            },
                            "required": ["content", "status"],
                        },
                    }
                },
                "required": ["todos"],
            },
            handler=lambda **kw: TODOS.update(kw["todos"]),
        )
    ]
)


def run_session(messages: list[dict[str, object]]):
    return run_loop(
        client=CLIENT,
        model=MODEL,
        system_prompt=SYSTEM,
        registry=REGISTRY,
        messages=messages,
    )


if __name__ == "__main__":
    repl(prompt="\033[36ms03 >> \033[0m", runner=run_session)

#!/usr/bin/env python3
# Harness: skills -- late-bound knowledge with discovery and activation.
"""
s05_skill_loading.py - Skill Discovery

The old lesson only taught "load a skill by name".
This rewrite keeps that idea but adds the two missing realities:

- skills come from multiple directories
- some skills activate only when matching file paths appear
"""

from __future__ import annotations

import re
from dataclasses import dataclass
from pathlib import Path
from typing import Any

from agents._shared import Tool, ToolRegistry, base_tools, get_model, make_client, repl, run_loop

try:
    import yaml
except ImportError:  # pragma: no cover - teaching path
    yaml = None


@dataclass
class Skill:
    name: str
    description: str
    body: str
    source: str
    paths: list[str]


class SkillLoader:
    def __init__(self, workdir: Path) -> None:
        self.workdir = workdir
        self.all_skills: dict[str, Skill] = {}
        self.active_skills: dict[str, Skill] = {}
        self._load_static_sources()

    def _parse_skill(self, file_path: Path) -> Skill:
        raw = file_path.read_text(encoding="utf-8")
        match = re.match(r"^---\n(.*?)\n---\n(.*)", raw, re.DOTALL)
        frontmatter: dict[str, Any] = {}
        body = raw.strip()
        if match:
            if yaml is not None:
                parsed = yaml.safe_load(match.group(1))
                frontmatter = parsed if isinstance(parsed, dict) else {}
            body = match.group(2).strip()
        name = str(frontmatter.get("name", file_path.parent.name))
        description = str(frontmatter.get("description", "No description provided."))
        paths_raw = frontmatter.get("paths", [])
        if isinstance(paths_raw, str):
            paths = [item.strip() for item in paths_raw.split(",") if item.strip()]
        elif isinstance(paths_raw, list):
            paths = [str(item).strip() for item in paths_raw if str(item).strip()]
        else:
            paths = []
        return Skill(
            name=name,
            description=description,
            body=body,
            source=str(file_path),
            paths=paths,
        )

    def _load_static_sources(self) -> None:
        candidate_dirs = [
            self.workdir / "skills",
            self.workdir / ".claude" / "skills",
        ]
        for directory in candidate_dirs:
            if not directory.exists():
                continue
            for file_path in sorted(directory.rglob("SKILL.md")):
                skill = self._parse_skill(file_path)
                self.all_skills[skill.name] = skill
                if not skill.paths:
                    self.active_skills[skill.name] = skill

    def activate_for_paths(self, paths: list[str]) -> str:
        activated: list[str] = []
        normalized = [path.replace("\\", "/") for path in paths]
        for skill in self.all_skills.values():
            if not skill.paths or skill.name in self.active_skills:
                continue
            for pattern in skill.paths:
                pattern = pattern.replace("\\", "/").strip()
                if not pattern:
                    continue
                if any(pattern in path for path in normalized):
                    self.active_skills[skill.name] = skill
                    activated.append(skill.name)
                    break
        if not activated:
            return "No conditional skills activated."
        return "Activated skills: " + ", ".join(sorted(activated))

    def list_active(self) -> str:
        if not self.active_skills:
            return "(no active skills)"
        return "\n".join(
            f"- {skill.name}: {skill.description}"
            for skill in sorted(self.active_skills.values(), key=lambda item: item.name)
        )

    def load(self, name: str) -> str:
        skill = self.active_skills.get(name)
        if not skill:
            available = ", ".join(sorted(self.active_skills)) or "(none)"
            return f"Error: unknown or inactive skill '{name}'. Active skills: {available}"
        return (
            f"<skill name=\"{skill.name}\" source=\"{skill.source}\">\n"
            f"{skill.body}\n"
            "</skill>"
        )


WORKDIR = Path.cwd()
MODEL = get_model()
CLIENT = make_client()
SKILLS = SkillLoader(WORKDIR)
SYSTEM = f"""You are a coding agent at {WORKDIR}.
Skills are loaded late.
You can inspect active skills in the system prompt, activate conditional skills
from file paths, then load the full body when needed.

Active skills:
{SKILLS.list_active()}"""

REGISTRY = ToolRegistry(
    base_tools(WORKDIR)
    + [
        Tool(
            name="activate_skills",
            description="Activate conditional skills that match touched paths.",
            input_schema={
                "type": "object",
                "properties": {
                    "paths": {
                        "type": "array",
                        "items": {"type": "string"},
                    }
                },
                "required": ["paths"],
            },
            handler=lambda **kw: SKILLS.activate_for_paths(kw["paths"]),
        ),
        Tool(
            name="load_skill",
            description="Load the full body of an active skill.",
            input_schema={
                "type": "object",
                "properties": {"name": {"type": "string"}},
                "required": ["name"],
            },
            handler=lambda **kw: SKILLS.load(kw["name"]),
        ),
    ]
)


def run_session(messages: list[dict[str, object]]):
    return run_loop(
        client=CLIENT,
        model=MODEL,
        system_prompt=SYSTEM,
        registry=REGISTRY,
        messages=messages,
    )


if __name__ == "__main__":
    repl(prompt="\033[36ms05 >> \033[0m", runner=run_session)

#!/usr/bin/env python3
# Harness: context management -- not one compact, but a stack of interventions.
"""
s06_context_compact.py - Context Management Stack

The correction here is the biggest one in the course.
We no longer teach a single three-stage compact pipeline as if that were the
whole story. Instead we model a stack:

- tool-result budgeting for oversized history
- micro summaries for stale detail
- manual compaction for explicit resets
"""

from __future__ import annotations

import json
import time
from pathlib import Path
from typing import Any

from agents._shared import (
    Tool,
    ToolRegistry,
    base_tools,
    get_model,
    make_client,
    repl,
    run_loop,
    summarize_messages,
)


class ContextManager:
    def __init__(self, workdir: Path) -> None:
        self.workdir = workdir
        self.transcript_dir = workdir / ".transcripts"
        self.transcript_dir.mkdir(exist_ok=True)

    def estimate_tokens(self, messages: list[dict[str, Any]]) -> int:
        return len(json.dumps(messages, default=str, ensure_ascii=False)) // 4

    def apply_result_budget(self, messages: list[dict[str, Any]]) -> None:
        tool_results: list[dict[str, Any]] = []
        for message in messages:
            if message["role"] == "user" and isinstance(message.get("content"), list):
                for part in message["content"]:
                    if isinstance(part, dict) and part.get("type") == "tool_result":
                        tool_results.append(part)
        for part in tool_results[:-4]:
            content = part.get("content")
            if isinstance(content, str) and len(content) > 500:
                part["content"] = content[:240] + "\n...[truncated by result budget]"

    def apply_micro_summary(self, messages: list[dict[str, Any]]) -> None:
        assistant_turns = [msg for msg in messages if msg["role"] == "assistant"]
        if len(assistant_turns) < 8:
            return
        for message in messages[:-6]:
            if message["role"] != "user":
                continue
            content = message.get("content")
            if isinstance(content, str) and len(content) > 300:
                message["content"] = content[:180] + "\n...[micro-summary placeholder]"

    def compact_now(self, messages: list[dict[str, Any]], reason: str) -> str:
        transcript_path = self.transcript_dir / f"compact_{int(time.time())}.jsonl"
        with transcript_path.open("w", encoding="utf-8") as handle:
            for message in messages:
                handle.write(json.dumps(message, default=str, ensure_ascii=False) + "\n")
        summary = summarize_messages(messages, keep_last=10)
        messages[:] = [
            {
                "role": "user",
                "content": (
                    "<compact-boundary>\n"
                    f"Reason: {reason}\n"
                    f"Transcript: {transcript_path}\n"
                    "Recent continuity summary:\n"
                    f"{summary}\n"
                    "</compact-boundary>"
                ),
            }
        ]
        return f"Conversation compacted. Transcript saved to {transcript_path}"


WORKDIR = Path.cwd()
MODEL = get_model()
CLIENT = make_client()
CTX = ContextManager(WORKDIR)
SYSTEM = f"""You are a coding agent at {WORKDIR}.
Manage context strategically.
Assume the harness can trim old tool results, replace stale detail with
micro-summaries, and compact the session when asked."""

_pending_manual_compact = {"reason": None}


def compact_handler(reason: str = "manual compact requested") -> str:
    _pending_manual_compact["reason"] = reason
    return "Compact requested. Finish the current tool turn, then reset the active context."


REGISTRY = ToolRegistry(
    base_tools(WORKDIR)
    + [
        Tool(
            name="compact",
            description="Create a compact boundary and keep only a continuity summary in context.",
            input_schema={
                "type": "object",
                "properties": {"reason": {"type": "string"}},
            },
            handler=lambda **kw: compact_handler(kw.get("reason", "manual compact requested")),
        )
    ]
)


def before_request(messages: list[dict[str, Any]]) -> None:
    CTX.apply_result_budget(messages)
    CTX.apply_micro_summary(messages)
    if CTX.estimate_tokens(messages) > 50_000:
        CTX.compact_now(messages, "token threshold crossed")


def run_session(messages: list[dict[str, object]]):
    response = run_loop(
        client=CLIENT,
        model=MODEL,
        system_prompt=SYSTEM,
        registry=REGISTRY,
        messages=messages,
        before_request=before_request,
    )
    if _pending_manual_compact["reason"]:
        reason = str(_pending_manual_compact["reason"])
        _pending_manual_compact["reason"] = None
        CTX.compact_now(messages, reason)
    return response


if __name__ == "__main__":
    repl(prompt="\033[36ms06 >> \033[0m", runner=run_session)

#!/usr/bin/env python3
# Harness: persistent tasks -- durable state outside the conversation transcript.
"""
s07_task_system.py - Persistent Task Runtime

This chapter upgrades the old "task graph in the repo" lesson.
The new teaching version keeps file-backed tasks, but makes the control-plane
idea explicit:

- tasks live outside conversation history
- task-list identity is separate from the session transcript
- dependencies and ownership survive compaction
"""

from __future__ import annotations

import json
import time
from pathlib import Path

from agents._shared import Tool, ToolRegistry, base_tools, get_model, make_client, repl, run_loop


class TaskStore:
    def __init__(self, root: Path, task_list_id: str = "default") -> None:
        self.root = root / ".lrcc" / "tasks" / task_list_id
        self.root.mkdir(parents=True, exist_ok=True)
        self.high_water_mark = self.root / ".high-water-mark"

    def _next_id(self) -> str:
        existing = [int(path.stem) for path in self.root.glob("*.json") if path.stem.isdigit()]
        current_mark = int(self.high_water_mark.read_text() or "0") if self.high_water_mark.exists() else 0
        next_id = max(existing + [current_mark], default=0) + 1
        self.high_water_mark.write_text(str(next_id), encoding="utf-8")
        return str(next_id)

    def _path(self, task_id: str) -> Path:
        return self.root / f"{task_id}.json"

    def create(self, subject: str, description: str = "") -> str:
        task = {
            "id": self._next_id(),
            "subject": subject,
            "description": description,
            "status": "pending",
            "owner": "",
            "blocked_by": [],
            "blocks": [],
            "created_at": time.time(),
            "updated_at": time.time(),
        }
        self._path(task["id"]).write_text(json.dumps(task, indent=2), encoding="utf-8")
        return json.dumps(task, indent=2)

    def get(self, task_id: str) -> str:
        path = self._path(task_id)
        if not path.exists():
            return f"Error: task {task_id} not found"
        return path.read_text(encoding="utf-8")

    def list_all(self) -> str:
        tasks = [
            json.loads(path.read_text(encoding="utf-8"))
            for path in sorted(self.root.glob("*.json"))
            if path.stem.isdigit()
        ]
        if not tasks:
            return "No tasks."
        lines: list[str] = []
        for task in tasks:
            marker = {
                "pending": "[ ]",
                "in_progress": "[>]",
                "completed": "[x]",
            }.get(task["status"], "[?]")
            owner = f" owner={task['owner']}" if task.get("owner") else ""
            blocked = (
                f" blocked_by={task['blocked_by']}"
                if task.get("blocked_by")
                else ""
            )
            lines.append(f"{marker} #{task['id']}: {task['subject']}{owner}{blocked}")
        return "\n".join(lines)

    def update(
        self,
        task_id: str,
        *,
        status: str | None = None,
        owner: str | None = None,
        add_blocked_by: list[str] | None = None,
    ) -> str:
        path = self._path(task_id)
        if not path.exists():
            return f"Error: task {task_id} not found"
        task = json.loads(path.read_text(encoding="utf-8"))
        if status is not None:
            if status not in {"pending", "in_progress", "completed"}:
                return f"Error: invalid status {status!r}"
            task["status"] = status
        if owner is not None:
            task["owner"] = owner
        if add_blocked_by:
            merged = list(dict.fromkeys(task.get("blocked_by", []) + add_blocked_by))
            task["blocked_by"] = merged
        task["updated_at"] = time.time()
        path.write_text(json.dumps(task, indent=2), encoding="utf-8")
        if status == "completed":
            self._clear_dependency(task_id)
        return json.dumps(task, indent=2)

    def _clear_dependency(self, completed_id: str) -> None:
        for path in self.root.glob("*.json"):
            if not path.stem.isdigit():
                continue
            task = json.loads(path.read_text(encoding="utf-8"))
            if completed_id in task.get("blocked_by", []):
                task["blocked_by"] = [item for item in task["blocked_by"] if item != completed_id]
                task["updated_at"] = time.time()
                path.write_text(json.dumps(task, indent=2), encoding="utf-8")


WORKDIR = Path.cwd()
MODEL = get_model()
CLIENT = make_client()
TASKS = TaskStore(WORKDIR)
SYSTEM = f"""You are a coding agent at {WORKDIR}.
Use the persistent task tools for long-lived work tracking.
Remember that tasks outlive the current transcript."""

REGISTRY = ToolRegistry(
    base_tools(WORKDIR)
    + [
        Tool(
            name="task_create",
            description="Create a durable task in the task list.",
            input_schema={
                "type": "object",
                "properties": {
                    "subject": {"type": "string"},
                    "description": {"type": "string"},
                },
                "required": ["subject"],
            },
            handler=lambda **kw: TASKS.create(kw["subject"], kw.get("description", "")),
        ),
        Tool(
            name="task_get",
            description="Read a task by ID.",
            input_schema={
                "type": "object",
                "properties": {"task_id": {"type": "string"}},
                "required": ["task_id"],
            },
            handler=lambda **kw: TASKS.get(kw["task_id"]),
        ),
        Tool(
            name="task_list",
            description="List all tasks in the current task list.",
            input_schema={"type": "object", "properties": {}},
            handler=lambda **kw: TASKS.list_all(),
        ),
        Tool(
            name="task_update",
            description="Update task status, owner, or dependencies.",
            input_schema={
                "type": "object",
                "properties": {
                    "task_id": {"type": "string"},
                    "status": {
                        "type": "string",
                        "enum": ["pending", "in_progress", "completed"],
                    },
                    "owner": {"type": "string"},
                    "add_blocked_by": {
                        "type": "array",
                        "items": {"type": "string"},
                    },
                },
                "required": ["task_id"],
            },
            handler=lambda **kw: TASKS.update(
                kw["task_id"],
                status=kw.get("status"),
                owner=kw.get("owner"),
                add_blocked_by=kw.get("add_blocked_by"),
            ),
        ),
    ]
)


def run_session(messages: list[dict[str, object]]):
    return run_loop(
        client=CLIENT,
        model=MODEL,
        system_prompt=SYSTEM,
        registry=REGISTRY,
        messages=messages,
    )


if __name__ == "__main__":
    repl(prompt="\033[36ms07 >> \033[0m", runner=run_session)

#!/usr/bin/env python3
# Harness: background runtime -- slow work should not stall the foreground loop.
"""
s08_background_tasks.py - Background Runtime

The old lesson only modeled background shell commands.
This rewrite keeps that core idea, but frames it as a runtime concern:

- foreground reasoning stays responsive
- background tasks produce notifications
- the harness owns task lifecycle, not the model
"""

from __future__ import annotations

import subprocess
import threading
import uuid
from pathlib import Path

from agents._shared import Tool, ToolRegistry, base_tools, get_model, make_client, repl, run_loop


class BackgroundManager:
    def __init__(self, workdir: Path) -> None:
        self.workdir = workdir
        self.tasks: dict[str, dict[str, str | None]] = {}
        self._notifications: list[dict[str, str]] = []
        self._lock = threading.Lock()

    def run(self, command: str) -> str:
        task_id = str(uuid.uuid4())[:8]
        self.tasks[task_id] = {
            "status": "running",
            "command": command,
            "result": None,
        }
        thread = threading.Thread(target=self._execute, args=(task_id, command), daemon=True)
        thread.start()
        return f"Background task {task_id} launched: {command[:80]}"

    def _execute(self, task_id: str, command: str) -> None:
        try:
            result = subprocess.run(
                command,
                shell=True,
                cwd=self.workdir,
                capture_output=True,
                text=True,
                timeout=300,
            )
            output = (result.stdout + result.stderr).strip() or "(no output)"
            status = "completed"
        except subprocess.TimeoutExpired:
            output = "Error: Timeout (300s)"
            status = "timeout"
        self.tasks[task_id]["status"] = status
        self.tasks[task_id]["result"] = output[:50_000]
        with self._lock:
            self._notifications.append(
                {
                    "task_id": task_id,
                    "status": status,
                    "result": output[:500],
                }
            )

    def check(self, task_id: str | None = None) -> str:
        if task_id:
            task = self.tasks.get(task_id)
            if not task:
                return f"Error: unknown task {task_id}"
            result = task.get("result")
            if result is None:
                return f"[{task['status']}] (running)"
            return f"[{task['status']}] {result}"
        if not self.tasks:
            return "No background tasks."
        return "\n".join(
            f"{task_id}: [{task['status']}] {task['command']}"
            for task_id, task in sorted(self.tasks.items())
        )

    def drain_notifications(self) -> list[dict[str, str]]:
        with self._lock:
            notifications = list(self._notifications)
            self._notifications.clear()
        return notifications


WORKDIR = Path.cwd()
MODEL = get_model()
CLIENT = make_client()
BG = BackgroundManager(WORKDIR)
SYSTEM = f"""You are a coding agent at {WORKDIR}.
Use background_run for slow commands.
Treat notifications as runtime events injected by the harness."""

REGISTRY = ToolRegistry(
    base_tools(WORKDIR)
    + [
        Tool(
            name="background_run",
            description="Launch a long-running shell command in the background.",
            input_schema={
                "type": "object",
                "properties": {"command": {"type": "string"}},
                "required": ["command"],
            },
            handler=lambda **kw: BG.run(kw["command"]),
        ),
        Tool(
            name="background_check",
            description="Inspect one background task or list them all.",
            input_schema={
                "type": "object",
                "properties": {"task_id": {"type": "string"}},
            },
            handler=lambda **kw: BG.check(kw.get("task_id")),
        ),
    ]
)


def before_request(messages: list[dict[str, object]]) -> None:
    notifications = BG.drain_notifications()
    if not notifications:
        return
    payload = "\n".join(
        f"[bg:{item['task_id']}] {item['status']}: {item['result']}"
        for item in notifications
    )
    messages.append(
        {
            "role": "user",
            "content": f"<task-notifications>\n{payload}\n</task-notifications>",
        }
    )


def run_session(messages: list[dict[str, object]]):
    return run_loop(
        client=CLIENT,
        model=MODEL,
        system_prompt=SYSTEM,
        registry=REGISTRY,
        messages=messages,
        before_request=before_request,
    )


if __name__ == "__main__":
    repl(prompt="\033[36ms08 >> \033[0m", runner=run_session)

#!/usr/bin/env python3
# Harness: shared collaboration state -- teammates, inboxes, and team identity.
"""
s09_agent_teams.py - Team Mailboxes

This chapter keeps the durable lesson from the old course:
multi-agent collaboration needs explicit shared state.

The modernized version emphasizes three shared artifacts:

- a team roster
- mailbox files
- a shared task-list identity
"""

from __future__ import annotations

import json
import threading
import time
from pathlib import Path

from agents._shared import Tool, ToolRegistry, base_tools, get_model, make_client, repl, run_loop


class MailboxBus:
    def __init__(self, inbox_dir: Path) -> None:
        self.inbox_dir = inbox_dir
        self.inbox_dir.mkdir(parents=True, exist_ok=True)

    def send(self, sender: str, recipient: str, message: str, summary: str = "") -> str:
        payload = {
            "from": sender,
            "message": message,
            "summary": summary,
            "timestamp": time.time(),
        }
        path = self.inbox_dir / f"{recipient}.jsonl"
        with path.open("a", encoding="utf-8") as handle:
            handle.write(json.dumps(payload) + "\n")
        return f"Sent message to {recipient}"

    def read(self, recipient: str) -> list[dict[str, object]]:
        path = self.inbox_dir / f"{recipient}.jsonl"
        if not path.exists():
            return []
        rows = [
            json.loads(line)
            for line in path.read_text(encoding="utf-8").splitlines()
            if line.strip()
        ]
        path.write_text("", encoding="utf-8")
        return rows


class TeamManager:
    def __init__(self, root: Path, bus: MailboxBus) -> None:
        self.root = root / ".lrcc" / "team"
        self.root.mkdir(parents=True, exist_ok=True)
        self.config_path = self.root / "config.json"
        self.bus = bus
        self.config = self._load()
        self.threads: dict[str, threading.Thread] = {}

    def _load(self) -> dict[str, object]:
        if self.config_path.exists():
            return json.loads(self.config_path.read_text(encoding="utf-8"))
        return {"team_name": "default", "members": []}

    def _save(self) -> None:
        self.config_path.write_text(json.dumps(self.config, indent=2), encoding="utf-8")

    def spawn(self, name: str, role: str, prompt: str) -> str:
        members = self.config["members"]
        member = next((item for item in members if item["name"] == name), None)
        if member is None:
            member = {"name": name, "role": role, "status": "working"}
            members.append(member)
        else:
            member["role"] = role
            member["status"] = "working"
        self._save()

        def teammate_loop() -> None:
            messages = [{"role": "user", "content": prompt}]
            system = (
                f"You are teammate '{name}' with role '{role}'. "
                "Use send_message to coordinate. Stay focused and concise."
            )
            registry = ToolRegistry(
                base_tools(Path.cwd())
                + [
                    Tool(
                        name="send_message",
                        description="Send a message to another teammate.",
                        input_schema={
                            "type": "object",
                            "properties": {
                                "to": {"type": "string"},
                                "message": {"type": "string"},
                                "summary": {"type": "string"},
                            },
                            "required": ["to", "message"],
                        },
                        handler=lambda **kw: self.bus.send(
                            name,
                            kw["to"],
                            kw["message"],
                            kw.get("summary", ""),
                        ),
                    )
                ]
            )

            def before_request(history: list[dict[str, object]]) -> None:
                inbox = self.bus.read(name)
                if inbox:
                    history.append(
                        {
                            "role": "user",
                            "content": "<inbox>\n" + json.dumps(inbox, indent=2) + "\n</inbox>",
                        }
                    )

            try:
                run_loop(
                    client=make_client(),
                    model=get_model(),
                    system_prompt=system,
                    registry=registry,
                    messages=messages,
                    before_request=before_request,
                    max_turns=20,
                )
            finally:
                member["status"] = "idle"
                self._save()

        thread = threading.Thread(target=teammate_loop, daemon=True)
        self.threads[name] = thread
        thread.start()
        return f"Spawned teammate '{name}' ({role})"

    def list_members(self) -> str:
        members = self.config["members"]
        if not members:
            return "No teammates."
        lines = [f"Team: {self.config['team_name']}"]
        for member in members:
            lines.append(f"- {member['name']} ({member['role']}): {member['status']}")
        return "\n".join(lines)


WORKDIR = Path.cwd()
MODEL = get_model()
CLIENT = make_client()
BUS = MailboxBus(WORKDIR / ".lrcc" / "team" / "inbox")
TEAM = TeamManager(WORKDIR, BUS)
SYSTEM = f"""You are a team lead at {WORKDIR}.
Use team_spawn to create persistent teammates and send_message to coordinate.
Treat mailboxes as shared collaboration state, not ad-hoc chat."""

REGISTRY = ToolRegistry(
    base_tools(WORKDIR)
    + [
        Tool(
            name="team_spawn",
            description="Create or resume a persistent teammate.",
            input_schema={
                "type": "object",
                "properties": {
                    "name": {"type": "string"},
                    "role": {"type": "string"},
                    "prompt": {"type": "string"},
                },
                "required": ["name", "role", "prompt"],
            },
            handler=lambda **kw: TEAM.spawn(kw["name"], kw["role"], kw["prompt"]),
        ),
        Tool(
            name="send_message",
            description="Send a mailbox message to a teammate.",
            input_schema={
                "type": "object",
                "properties": {
                    "to": {"type": "string"},
                    "message": {"type": "string"},
                    "summary": {"type": "string"},
                },
                "required": ["to", "message"],
            },
            handler=lambda **kw: BUS.send("lead", kw["to"], kw["message"], kw.get("summary", "")),
        ),
        Tool(
            name="read_inbox",
            description="Read and drain the lead inbox.",
            input_schema={"type": "object", "properties": {}},
            handler=lambda **kw: json.dumps(BUS.read("lead"), indent=2) or "[]",
        ),
        Tool(
            name="team_list",
            description="List team members and statuses.",
            input_schema={"type": "object", "properties": {}},
            handler=lambda **kw: TEAM.list_members(),
        ),
    ]
)


def run_session(messages: list[dict[str, object]]):
    return run_loop(
        client=CLIENT,
        model=MODEL,
        system_prompt=SYSTEM,
        registry=REGISTRY,
        messages=messages,
    )


if __name__ == "__main__":
    repl(prompt="\033[36ms09 >> \033[0m", runner=run_session)

#!/usr/bin/env python3
# Harness: structured coordination -- request IDs turn messages into protocols.
"""
s10_team_protocols.py - Team Protocols

This chapter keeps the mailbox model from s09 and adds a missing layer:
not every message should be plain chat.

The teaching version introduces two request/response protocols:

- shutdown approval
- plan approval
"""

from __future__ import annotations

import json
import time
import uuid
from pathlib import Path

from agents._shared import Tool, ToolRegistry, base_tools, get_model, make_client, repl, run_loop


class ProtocolState:
    def __init__(self, state_dir: Path) -> None:
        self.state_dir = state_dir
        self.state_dir.mkdir(parents=True, exist_ok=True)
        self.shutdown_requests: dict[str, dict[str, object]] = {}
        self.plan_requests: dict[str, dict[str, object]] = {}

    def request_shutdown(self, teammate: str, reason: str = "") -> str:
        request_id = str(uuid.uuid4())[:8]
        self.shutdown_requests[request_id] = {
            "target": teammate,
            "status": "pending",
            "reason": reason,
            "created_at": time.time(),
        }
        return json.dumps(self.shutdown_requests[request_id] | {"request_id": request_id}, indent=2)

    def submit_plan(self, teammate: str, plan: str) -> str:
        request_id = str(uuid.uuid4())[:8]
        self.plan_requests[request_id] = {
            "from": teammate,
            "plan": plan,
            "status": "pending",
            "created_at": time.time(),
        }
        return json.dumps(self.plan_requests[request_id] | {"request_id": request_id}, indent=2)

    def resolve(self, protocol: str, request_id: str, approve: bool, feedback: str = "") -> str:
        table = self.shutdown_requests if protocol == "shutdown" else self.plan_requests
        entry = table.get(request_id)
        if entry is None:
            return f"Error: unknown {protocol} request {request_id}"
        entry["status"] = "approved" if approve else "rejected"
        entry["feedback"] = feedback
        entry["resolved_at"] = time.time()
        return json.dumps(entry | {"request_id": request_id}, indent=2)

    def list_all(self) -> str:
        payload = {
            "shutdown_requests": self.shutdown_requests,
            "plan_requests": self.plan_requests,
        }
        return json.dumps(payload, indent=2) if any(payload.values()) else "No protocol state."


WORKDIR = Path.cwd()
MODEL = get_model()
CLIENT = make_client()
STATE = ProtocolState(WORKDIR / ".lrcc" / "protocols")
SYSTEM = f"""You are a coordinating agent at {WORKDIR}.
Use request IDs for non-trivial coordination.
Prefer structured approval protocols over ambiguous free-form messages."""

REGISTRY = ToolRegistry(
    base_tools(WORKDIR)
    + [
        Tool(
            name="request_shutdown",
            description="Open a structured shutdown request.",
            input_schema={
                "type": "object",
                "properties": {
                    "teammate": {"type": "string"},
                    "reason": {"type": "string"},
                },
                "required": ["teammate"],
            },
            handler=lambda **kw: STATE.request_shutdown(kw["teammate"], kw.get("reason", "")),
        ),
        Tool(
            name="respond_shutdown",
            description="Approve or reject a shutdown request.",
            input_schema={
                "type": "object",
                "properties": {
                    "request_id": {"type": "string"},
                    "approve": {"type": "boolean"},
                    "feedback": {"type": "string"},
                },
                "required": ["request_id", "approve"],
            },
            handler=lambda **kw: STATE.resolve(
                "shutdown",
                kw["request_id"],
                kw["approve"],
                kw.get("feedback", ""),
            ),
        ),
        Tool(
            name="submit_plan",
            description="Open a structured plan approval request.",
            input_schema={
                "type": "object",
                "properties": {
                    "teammate": {"type": "string"},
                    "plan": {"type": "string"},
                },
                "required": ["teammate", "plan"],
            },
            handler=lambda **kw: STATE.submit_plan(kw["teammate"], kw["plan"]),
        ),
        Tool(
            name="review_plan",
            description="Approve or reject a plan request.",
            input_schema={
                "type": "object",
                "properties": {
                    "request_id": {"type": "string"},
                    "approve": {"type": "boolean"},
                    "feedback": {"type": "string"},
                },
                "required": ["request_id", "approve"],
            },
            handler=lambda **kw: STATE.resolve(
                "plan",
                kw["request_id"],
                kw["approve"],
                kw.get("feedback", ""),
            ),
        ),
        Tool(
            name="protocol_state",
            description="Inspect current protocol trackers.",
            input_schema={"type": "object", "properties": {}},
            handler=lambda **kw: STATE.list_all(),
        ),
    ]
)


def run_session(messages: list[dict[str, object]]):
    return run_loop(
        client=CLIENT,
        model=MODEL,
        system_prompt=SYSTEM,
        registry=REGISTRY,
        messages=messages,
    )


if __name__ == "__main__":
    repl(prompt="\033[36ms10 >> \033[0m", runner=run_session)

#!/usr/bin/env python3
# Harness: execution isolation -- worktrees separate where tasks run.
"""
s12_worktree_task_isolation.py - Worktree Isolation

The last chapter keeps the core lesson:
tasks are control-plane state; isolation decides where execution happens.

This version teaches three linked records:

- task record
- worktree record
- lifecycle event log
"""

from __future__ import annotations

import json
import shutil
import subprocess
import time
from pathlib import Path

from agents._shared import Tool, ToolRegistry, base_tools, get_model, make_client, repl, run_loop


def detect_repo_root(cwd: Path) -> Path | None:
    try:
        result = subprocess.run(
            ["git", "rev-parse", "--show-toplevel"],
            cwd=cwd,
            capture_output=True,
            text=True,
            timeout=10,
        )
    except Exception:
        return None
    if result.returncode != 0:
        return None
    root = Path(result.stdout.strip())
    return root if root.exists() else None


class TaskBoard:
    def __init__(self, root: Path) -> None:
        self.root = root / ".lrcc" / "isolation" / "tasks"
        self.root.mkdir(parents=True, exist_ok=True)

    def create(self, subject: str) -> dict[str, object]:
        next_id = str(max([0] + [int(path.stem) for path in self.root.glob("*.json") if path.stem.isdigit()]) + 1)
        task = {
            "id": next_id,
            "subject": subject,
            "status": "pending",
            "worktree": "",
        }
        (self.root / f"{next_id}.json").write_text(json.dumps(task, indent=2), encoding="utf-8")
        return task

    def bind(self, task_id: str, worktree_name: str) -> dict[str, object]:
        path = self.root / f"{task_id}.json"
        if not path.exists():
            raise ValueError(f"Task {task_id} not found")
        task = json.loads(path.read_text(encoding="utf-8"))
        task["worktree"] = worktree_name
        if task["status"] == "pending":
            task["status"] = "in_progress"
        path.write_text(json.dumps(task, indent=2), encoding="utf-8")
        return task

    def complete(self, task_id: str) -> dict[str, object]:
        path = self.root / f"{task_id}.json"
        task = json.loads(path.read_text(encoding="utf-8"))
        task["status"] = "completed"
        path.write_text(json.dumps(task, indent=2), encoding="utf-8")
        return task

    def list_all(self) -> str:
        tasks = [json.loads(path.read_text(encoding="utf-8")) for path in sorted(self.root.glob("*.json"))]
        return json.dumps(tasks, indent=2) if tasks else "[]"


class EventLog:
    def __init__(self, path: Path) -> None:
        self.path = path
        self.path.parent.mkdir(parents=True, exist_ok=True)
        if not self.path.exists():
            self.path.write_text("", encoding="utf-8")

    def emit(self, event: str, **payload: object) -> None:
        record = {"event": event, "ts": time.time(), **payload}
        with self.path.open("a", encoding="utf-8") as handle:
            handle.write(json.dumps(record) + "\n")

    def recent(self, limit: int = 20) -> str:
        lines = self.path.read_text(encoding="utf-8").splitlines()[-limit:]
        return json.dumps([json.loads(line) for line in lines], indent=2) if lines else "[]"


class WorktreeStore:
    def __init__(self, repo_root: Path, tasks: TaskBoard, events: EventLog) -> None:
        self.repo_root = repo_root
        self.base = repo_root / ".lrcc" / "isolation" / "worktrees"
        self.base.mkdir(parents=True, exist_ok=True)
        self.index_path = self.base / "index.json"
        self.tasks = tasks
        self.events = events

    def _load_index(self) -> dict[str, object]:
        if self.index_path.exists():
            return json.loads(self.index_path.read_text(encoding="utf-8"))
        return {"worktrees": []}

    def _save_index(self, data: dict[str, object]) -> None:
        self.index_path.write_text(json.dumps(data, indent=2), encoding="utf-8")

    def create(self, name: str, task_id: str | None = None) -> str:
        worktree_path = self.base / name
        self.events.emit("worktree.create.before", name=name, task_id=task_id)
        if not worktree_path.exists():
            if detect_repo_root(self.repo_root):
                subprocess.run(
                    ["git", "worktree", "add", str(worktree_path), "-b", f"wt/{name}"],
                    cwd=self.repo_root,
                    capture_output=True,
                    text=True,
                    timeout=30,
                )
            else:
                worktree_path.mkdir(parents=True, exist_ok=True)
        index = self._load_index()
        record = {
            "name": name,
            "path": str(worktree_path),
            "branch": f"wt/{name}",
            "task_id": task_id,
            "status": "active",
        }
        index["worktrees"] = [item for item in index["worktrees"] if item["name"] != name] + [record]
        self._save_index(index)
        if task_id:
            self.tasks.bind(task_id, name)
        self.events.emit("worktree.create.after", worktree=record)
        return json.dumps(record, indent=2)

    def remove(self, name: str, complete_task: bool = False) -> str:
        index = self._load_index()
        record = next((item for item in index["worktrees"] if item["name"] == name), None)
        if record is None:
            return f"Error: worktree {name} not found"
        self.events.emit("worktree.remove.before", worktree=record)
        worktree_path = Path(record["path"])
        if worktree_path.exists() and worktree_path.is_dir():
            shutil.rmtree(worktree_path)
        record["status"] = "removed"
        self._save_index(index)
        if complete_task and record.get("task_id"):
            task = self.tasks.complete(str(record["task_id"]))
            self.events.emit("task.completed", task=task)
        self.events.emit("worktree.remove.after", worktree=record)
        return json.dumps(record, indent=2)

    def list_all(self) -> str:
        return json.dumps(self._load_index(), indent=2)


WORKDIR = Path.cwd()
REPO_ROOT = detect_repo_root(WORKDIR) or WORKDIR
MODEL = get_model()
CLIENT = make_client()
TASKS = TaskBoard(REPO_ROOT)
EVENTS = EventLog(REPO_ROOT / ".lrcc" / "isolation" / "events.jsonl")
WORKTREES = WorktreeStore(REPO_ROOT, TASKS, EVENTS)
SYSTEM = f"""You are a coding agent at {WORKDIR}.
Use task_create for the control plane and worktree_create for execution isolation.
Keep task identity and worktree identity linked."""

REGISTRY = ToolRegistry(
    base_tools(WORKDIR)
    + [
        Tool(
            name="task_create",
            description="Create a task before allocating an isolation lane.",
            input_schema={
                "type": "object",
                "properties": {"subject": {"type": "string"}},
                "required": ["subject"],
            },
            handler=lambda **kw: json.dumps(TASKS.create(kw["subject"]), indent=2),
        ),
        Tool(
            name="task_list",
            description="List task records.",
            input_schema={"type": "object", "properties": {}},
            handler=lambda **kw: TASKS.list_all(),
        ),
        Tool(
            name="worktree_create",
            description="Create an isolated execution lane and optionally bind it to a task.",
            input_schema={
                "type": "object",
                "properties": {
                    "name": {"type": "string"},
                    "task_id": {"type": "string"},
                },
                "required": ["name"],
            },
            handler=lambda **kw: WORKTREES.create(kw["name"], kw.get("task_id")),
        ),
        Tool(
            name="worktree_remove",
            description="Remove an isolated execution lane.",
            input_schema={
                "type": "object",
                "properties": {
                    "name": {"type": "string"},
                    "complete_task": {"type": "boolean"},
                },
                "required": ["name"],
            },
            handler=lambda **kw: WORKTREES.remove(kw["name"], kw.get("complete_task", False)),
        ),
        Tool(
            name="worktree_list",
            description="List isolation lanes.",
            input_schema={"type": "object", "properties": {}},
            handler=lambda **kw: WORKTREES.list_all(),
        ),
        Tool(
            name="worktree_events",
            description="Inspect lifecycle events for isolation lanes.",
            input_schema={
                "type": "object",
                "properties": {"limit": {"type": "integer"}},
            },
            handler=lambda **kw: EVENTS.recent(int(kw.get("limit", 20))),
        ),
    ]
)


def run_session(messages: list[dict[str, object]]):
    return run_loop(
        client=CLIENT,
        model=MODEL,
        system_prompt=SYSTEM,
        registry=REGISTRY,
        messages=messages,
    )


if __name__ == "__main__":
    repl(prompt="\033[36ms12 >> \033[0m", runner=run_session)
